{
    "level": "A1",
    "intro": "У питаннях з <strong>to be</strong> форма <strong>am / is / are</strong> стає <strong>перед підметом</strong>.",
    "rules": [
        {
            "label": "Am I...?",
            "color": "emerald",
            "text": "Починай питання з <strong>am</strong>, коли підмет <strong>I</strong>.",
            "example": "Am I late?"
        },
        {
            "label": "Is he / she / it...?",
            "color": "blue",
            "text": "З <strong>he / she / it</strong> став <strong>is</strong> перед підметом.",
            "example": "Is she at home?"
        },
        {
            "label": "Are you / we / they...?",
            "color": "amber",
            "text": "З <strong>you / we / they</strong> став <strong>are</strong> перед підметом.",
            "example": "Are they ready?"
        }
    ]
}

{
    "title": "1. Базові моделі питання",
    "intro": "Питання з to be будуються без do / does.",
    "items": [
        {
            "label": "I",
            "title": "Am I ...?",
            "subtitle": "Am I early?"
        },
        {
            "label": "He / She / It",
            "title": "Is he / she / it ...?",
            "subtitle": "Is he busy? / Is it cold?"
        },
        {
            "label": "You / We / They",
            "title": "Are you / we / they ...?",
            "subtitle": "Are we late? / Are they at school?"
        },
        {
            "label": "Short Answers",
            "title": "Yes, ... am / is / are.",
            "subtitle": "Yes, I am. / No, he isn't. / Yes, they are."
        }
    ]
}

{
    "title": "2. Як відповідати коротко",
    "sections": [
        {
            "label": "Yes",
            "color": "emerald",
            "description": "У короткій стверджувальній відповіді повтори форму <strong>am / is / are</strong>.",
            "examples": [
                {
                    "en": "Are you tired? — Yes, I am.",
                    "ua": "Так, я втомлений."
                },
                {
                    "en": "Is she here? — Yes, she is.",
                    "ua": "Так, вона тут."
                }
            ]
        },
        {
            "label": "No",
            "color": "blue",
            "description": "У короткій заперечній відповіді часто вживають скорочення <strong>isn't / aren't</strong>.",
            "examples": [
                {
                    "en": "Is he busy? — No, he isn't.",
                    "ua": "Ні, він не зайнятий."
                },
                {
                    "en": "Are they at home? — No, they aren't.",
                    "ua": "Ні, вони не вдома."
                }
            ]
        },
        {
            "label": "Порядок слів",
            "color": "amber",
            "description": "Порівняй ствердження і питання: форма <strong>to be</strong> переходить перед підметом.",
            "examples": [
                {
                    "en": "She is ready. → Is she ready?",
                    "ua": "Інверсія з to be."
                },
                {
                    "en": "They are at school. → Are they at school?",
                    "ua": "Без do / does."
                }
            ]
        }
    ]
}

{
    "title": "3. Питання і коротка відповідь",
    "intro": "У відповіді не повторюй усе речення: достатньо короткої форми.",
    "rows": [
        {
            "en": "Am I late?",
            "ua": "Yes, you are. / No, you aren't.",
            "note": "У відповіді на Am I...? часто кажуть you are / you aren't."
        },
        {
            "en": "Is she your teacher?",
            "ua": "Yes, she is. / No, she isn't.",
            "note": "is → she is / she isn't"
        },
        {
            "en": "Are they ready?",
            "ua": "Yes, they are. / No, they aren't.",
            "note": "are → they are / they aren't"
        }
    ],
    "warning": "📌 Не кажи <strong>Do they are...?</strong> або <strong>Yes, they do.</strong>"
}

{
    "title": "4. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Залишати порядок слів як у ствердженні.",
            "wrong": "❌ She is ready?",
            "right": "✅ <span class=\"font-mono\">Is she ready?</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Додавати do / does до to be.",
            "wrong": "❌ Do they are at home?",
            "right": "✅ <span class=\"font-mono\">Are they at home?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Давати коротку відповідь з do.",
            "wrong": "❌ Yes, she does.",
            "right": "✅ <span class=\"font-mono\">Yes, she is.</span>"
        }
    ]
}

{
    "title": "5. Короткий підсумок",
    "items": [
        "Питання з <strong>to be</strong> = <strong>am / is / are + subject</strong>.",
        "З <strong>I</strong> починай з <strong>Am I...?</strong>",
        "З <strong>he / she / it</strong> починай з <strong>Is...?</strong>",
        "З <strong>you / we / they</strong> починай з <strong>Are...?</strong>",
        "У коротких відповідях повторюй форму <strong>to be</strong>: <strong>Yes, I am. / No, he isn't.</strong>"
    ]
}

